<?php
namespace App\Http\Controllers;use App\Models\{Order,OrderCompletionProof};use App\Services\Orders\OrderCompletionService;use Illuminate\Http\Request;class OrderCompletionController extends Controller{public function submit(Request $r,Order $order,OrderCompletionService $s){$d=$r->validate(['worker_note'=>'required|string|max:5000']);$s->submitProof($order,$r->user(),$d);return back()->with('status','Completion proof submitted. Waiting for customer confirmation.');}public function accept(Request $r,OrderCompletionProof $proof,OrderCompletionService $s){$d=$r->validate(['note'=>'nullable|string|max:2000']);$s->acceptByCustomer($proof,$r->user(),$d['note']??null);return back()->with('status','Completion proof accepted. Payment and payout remain separate.');}public function dispute(Request $r,OrderCompletionProof $proof,OrderCompletionService $s){$d=$r->validate(['reason'=>'required|string|max:5000']);$s->disputeByCustomer($proof,$r->user(),$d['reason']);return redirect()->route('account.support.create');}}